export function initialize(sentinelElement, dotNetHelper) {
    const observer = new IntersectionObserver(async (entries) => {
        if (entries[0].isIntersecting) {
            await dotNetHelper.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '100px' });

    observer.observe(sentinelElement);

    return { observer, sentinelElement };
}

export function dispose(instance) {
    if (instance?.observer) {
        instance.observer.unobserve(instance.sentinelElement);
        instance.observer.disconnect();
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observerInstance;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;
    private bool hasRenderedOnce;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            hasRenderedOnce = true;
            await SetupObserver();
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Re-attach observer when HasMore transitions back to true after items change
        if (hasRenderedOnce && HasMore && observerInstance is null)
        {
            await Task.Yield(); // let the sentinel render first
            await SetupObserver();
        }
    }

    private async Task SetupObserver()
    {
        if (!HasMore) return;

        dotNetRef ??= DotNetObjectReference.Create(this);
        module ??= await JS.InvokeAsync<IJSObjectReference>(
            "import", "./js/infinite-scroll.js");

        observerInstance = await module.InvokeAsync<IJSObjectReference>(
            "initialize", sentinelRef, dotNetRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore) return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;

        if (!HasMore)
        {
            await DisposeObserver();
        }

        StateHasChanged();
    }

    private async Task DisposeObserver()
    {
        if (observerInstance is not null && module is not null)
        {
            await module.InvokeVoidAsync("dispose", observerInstance);
            observerInstance = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await DisposeObserver();
        dotNetRef?.Dispose();

        if (module is not null)
        {
            await module.DisposeAsync();
        }
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid rgba(0, 0, 0, 0.1);
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to {
        transform: rotate(360deg);
    }
}

